#include <stdio.h>
#include <stdlib.h>

// Define the structure for the graph
typedef struct {
    int numVertices;
    int** adj;
} Graph;

// Function to create a graph
Graph* createGraph(int numVertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numVertices = numVertices;
    graph->adj = (int**) malloc(numVertices * sizeof(int*));
    for (int i = 0; i < numVertices; i++) {
        graph->adj[i] = (int*) malloc(numVertices * sizeof(int));
        for (int j = 0; j < numVertices; j++) {
            graph->adj[i][j] = 0;
        }
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    graph->adj[src][dest] = 1;
    graph->adj[dest][src] = 1;
}

// Function to find articulation points
void findArticulationPoints(Graph* graph) {
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    int* tin = (int*) malloc(graph->numVertices * sizeof(int));
    int* low = (int*) malloc(graph->numVertices * sizeof(int));
    int* mark = (int*) malloc(graph->numVertices * sizeof(int));
    int timer = 0;

    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
        tin[i] = -1;
        low[i] = -1;
        mark[i] = 0;
    }

    for (int i = 0; i < graph->numVertices; i++) {
        if (!visited[i]) {
            dfs(graph, i, -1, visited, tin, low, mark, &timer);
        }
    }

    for (int i = 0; i < graph->numVertices; i++) {
        if (mark[i]) {
            printf("%d ", i);
        }
    }
    printf("\n");
}

// Function to perform DFS
void dfs(Graph* graph, int node, int parent, int* visited, int* tin, int* low, int* mark, int* timer) {
    visited[node] = 1;
    tin[node] = *timer;
    low[node] = *timer;
    (*timer)++;
    int child = 0;

    for (int i = 0; i < graph->numVertices; i++) {
        if (graph->adj[node][i]) {
            if (i == parent) continue;
            if (!visited[i]) {
                dfs(graph, i, node, visited, tin, low, mark, timer);
                low[node] = min(low[node], low[i]);
                if (low[i] >= tin[node] && parent != -1) {
                    mark[node] = 1;
                }
                child++;
            } else if (visited[i]) {
                low[node] = min(low[node], tin[i]);
            }
        }
    }

    if (parent == -1 && child > 1) {
        mark[node] = 1;
    }
}

// Function to find the minimum of two numbers
int min(int a, int b) {
    return (a < b) ? a : b;
}

